[System.Serializable]
public class ShopItem
{
    public string itemId;
    public string itemName;
    public int basePrice = 100;
    public int purchaseCount = 0;
    public int healthIncrease = 0;
    public int damageIncrease = 0;
    public int currencyPackAmount = 0;

    public int CalculatePrice()
    {
        return Mathf.Max(1, basePrice + (purchaseCount * (basePrice / 2)));
    }
}

public class ShopSystem : MonoBehaviour
{
    public PlayerStats player;
    public ShopItem[] items;

    public bool PurchaseItem(string itemId)
    {
        if (player == null || items == null)
            return false;

        for (int i = 0; i < items.Length; i++)
        {
            ShopItem item = items[i];
            if (item != null && item.itemId == itemId)
            {
                int price = item.CalculatePrice();

                if (!player.SpendCurrency(price))
                {
                    Debug.Log("Not enough currency for " + item.itemName);
                    return false;
                }

                ApplyItemEffect(item);
                item.purchaseCount++;
                Debug.Log("Purchased: " + item.itemName + " for " + price);
                return true;
            }
        }

        Debug.Log("Item not found: " + itemId);
        return false;
    }

    private void ApplyItemEffect(ShopItem item)
    {
        if (item.healthIncrease > 0)
        {
            player.maxHealth += item.healthIncrease;
            player.currentHealth = Mathf.Min(player.currentHealth + item.healthIncrease, player.maxHealth);
        }

        if (item.damageIncrease > 0)
        {
            player.baseDamage += item.damageIncrease;
        }

        if (item.currencyPackAmount > 0)
        {
            player.AddCurrency(item.currencyPackAmount);
        }
    }

    public int GetItemPrice(string itemId)
    {
        if (items == null)
            return -1;

        for (int i = 0; i < items.Length; i++)
        {
            if (items[i] != null && items[i].itemId == itemId)
            {
                return items[i].CalculatePrice();
            }
        }

        return -1;
    }
}